import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"📊 市場情緒日報 — 2026-05-01（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/2026-05-01.md","filePath":"Deep32Q知識庫/市場情緒/2026-05-01.md"}'),o={name:"Deep32Q知識庫/市場情緒/2026-05-01.md"};function i(n,t,d,h,s,p){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="📊-市場情緒日報-—-2026-05-01-週五" tabindex="-1">📊 市場情緒日報 — 2026-05-01（週五） <a class="header-anchor" href="#📊-市場情緒日報-—-2026-05-01-週五" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026-05-01（週五）&quot;">​</a></h1><blockquote><p>掃描時間：凌晨 5:00 Cron 自動觸發 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🌍-全球財經頭條重點-10-點摘要" tabindex="-1">🌍 全球財經頭條重點（10 點摘要） <a class="header-anchor" href="#🌍-全球財經頭條重點-10-點摘要" aria-label="Permalink to &quot;🌍 全球財經頭條重點（10 點摘要）&quot;">​</a></h2><h3 id="_1-🛢️-油價持續高檔震盪-阿聯正式退出-opec" tabindex="-1">1. 🛢️ 油價持續高檔震盪，阿聯正式退出 OPEC <a class="header-anchor" href="#_1-🛢️-油價持續高檔震盪-阿聯正式退出-opec" aria-label="Permalink to &quot;1. 🛢️ 油價持續高檔震盪，阿聯正式退出 OPEC&quot;">​</a></h3><p>5/1 阿聯酋正式退出 OPEC+，初期引發供過於憂慮導致油價短暫下跌，但隨即被伊朗衝突風險覆蓋。布蘭特原油一度突破 $126/桶後回落至 $111-$114 區間。S&amp;P Global 上修全年 WTI/Brent 預測，IEA 預估 2026 年全球石油需求將萎縮。</p><h3 id="_2-🔒-荷莫茲海峽持續封閉-2-000-艘船滯留波斯灣" tabindex="-1">2. 🔒 荷莫茲海峽持續封閉，2,000 艘船滯留波斯灣 <a class="header-anchor" href="#_2-🔒-荷莫茲海峽持續封閉-2-000-艘船滯留波斯灣" aria-label="Permalink to &quot;2. 🔒 荷莫茲海峽持續封閉，2,000 艘船滯留波斯灣&quot;">​</a></h3><p>商業船運仍實質停止，波斯灣滯留約 2,000 艘船。即使海峽重開，恢復正常水平需數個月（含排雷）。美國主導「Maritime Freedom Construct」國際聯盟（MFC），法國和英國僅願意在衝突結束後協助。伊朗警告「前所未見軍事行動」。</p><h3 id="_3-📈-全球央行凍結降息-通膨威脅持續" tabindex="-1">3. 📈 全球央行凍結降息，通膨威脅持續 <a class="header-anchor" href="#_3-📈-全球央行凍結降息-通膨威脅持續" aria-label="Permalink to &quot;3. 📈 全球央行凍結降息，通膨威脅持續&quot;">​</a></h3><p>英國央行、聯準會、日本央行、ECB 均暫停降息，評估中東衝突及荷莫茲封閉的經濟影響。市場承認通膨威脅仍在。美國聯準會 4/29 維持利率不變，降息預期進一步後退。</p><h3 id="_4-🇹🇼-台灣-q1-gdp-13-69-創近-39-年新高-5-月展望審慎樂觀" tabindex="-1">4. 🇹🇼 台灣 Q1 GDP 13.69% 創近 39 年新高，5 月展望審慎樂觀 <a class="header-anchor" href="#_4-🇹🇼-台灣-q1-gdp-13-69-創近-39-年新高-5-月展望審慎樂觀" aria-label="Permalink to &quot;4. 🇹🇼 台灣 Q1 GDP 13.69% 創近 39 年新高，5 月展望審慎樂觀&quot;">​</a></h3><p>台灣 Q1 實質 GDP 年增率 13.69%（近 39 年新高）。台經院預估全年 7.56%、中經院 7.22%、瑞銀 8%。5 月台股面臨短期震盪後有望上攻 41,000 點。Computex 題材 5 月提前反映。法人建議持股水位降至五至六成。</p><h3 id="_5-📊-台股-4-月漲幅-7-203-點創歷史-5-月面臨多重變數" tabindex="-1">5. 📊 台股 4 月漲幅 +7,203 點創歷史，5 月面臨多重變數 <a class="header-anchor" href="#_5-📊-台股-4-月漲幅-7-203-點創歷史-5-月面臨多重變數" aria-label="Permalink to &quot;5. 📊 台股 4 月漲幅 +7,203 點創歷史，5 月面臨多重變數&quot;">​</a></h3><p>台股 4 月創史上最強單月（+7,203 點），總市值 4.47 兆美元超越英國躍居全球第六。5 月風險：漲幅過大、KD 高檔交叉、融資居高、外資轉保守、油價通膨壓力。</p><h3 id="_6-💹-美股-s-p-500-維持高檔盤整-道瓊-4-30-大幅跳升" tabindex="-1">6. 💹 美股 S&amp;P 500 維持高檔盤整，道瓊 4/30 大幅跳升 <a class="header-anchor" href="#_6-💹-美股-s-p-500-維持高檔盤整-道瓊-4-30-大幅跳升" aria-label="Permalink to &quot;6. 💹 美股 S&amp;P 500 維持高檔盤整，道瓊 4/30 大幅跳升&quot;">​</a></h3><p>S&amp;P 500 維持多頭趨勢但進入盤整。道瓊 4/30 大幅跳升。歐元區 10 年期公債殖利率創 2011 年來最高。比特幣 4 月暴漲 14.5% 至 $94,256。</p><h3 id="_7-🏛️-ieepa-關稅退款-5-11-開始-trump-規劃替代關稅" tabindex="-1">7. 🏛️ IEEPA 關稅退款 5/11 開始，Trump 規劃替代關稅 <a class="header-anchor" href="#_7-🏛️-ieepa-關稅退款-5-11-開始-trump-規劃替代關稅" aria-label="Permalink to &quot;7. 🏛️ IEEPA 關稅退款 5/11 開始，Trump 規劃替代關稅&quot;">​</a></h3><p>首批 IEEPA 關稅退款約 $1,660 億預計 5/11 發放（最高法院判決非法）。Trump 已啟動 Section 122 全球關稅 10%（至 7/24 到期）。USTR 對 60 個經濟體舉行 Section 301 聽證會（強迫勞動 + 產能過剩）。</p><h3 id="_8-🇨🇳-中國-5-1-起對非洲-53-國零關稅-尋求貿易夥伴" tabindex="-1">8. 🇨🇳 中國 5/1 起對非洲 53 國零關稅，尋求貿易夥伴 <a class="header-anchor" href="#_8-🇨🇳-中國-5-1-起對非洲-53-國零關稅-尋求貿易夥伴" aria-label="Permalink to &quot;8. 🇨🇳 中國 5/1 起對非洲 53 國零關稅，尋求貿易夥伴&quot;">​</a></h3><p>中國 5/1 起對所有建交非洲國家實施零關稅（至 2028/4/30），強化南南合作。同時，中國工廠 4 月活動持續擴張，但全球能源干擾影響供應鏈。</p><h3 id="_9-🇯🇵-日本央行-0-75-利率鷹派分歧-6-月升息機率-74" tabindex="-1">9. 🇯🇵 日本央行 0.75% 利率鷹派分歧，6 月升息機率 74% <a class="header-anchor" href="#_9-🇯🇵-日本央行-0-75-利率鷹派分歧-6-月升息機率-74" aria-label="Permalink to &quot;9. 🇯🇵 日本央行 0.75% 利率鷹派分歧，6 月升息機率 74%&quot;">​</a></h3><p>日銀 6-3 投票維持利率，鷹派異議者眾多。上修核心通膨預測至 2.8%，下修成長率至 0.5%。日圓因鷹派立場升值。市場定價 6 月升息機率達 74%。</p><h3 id="_10-🌐-iea-下修全球石油需求-2026-年恐萎縮" tabindex="-1">10. 🌐 IEA 下修全球石油需求，2026 年恐萎縮 <a class="header-anchor" href="#_10-🌐-iea-下修全球石油需求-2026-年恐萎縮" aria-label="Permalink to &quot;10. 🌐 IEA 下修全球石油需求，2026 年恐萎縮&quot;">​</a></h3><p>國際能源署（IEA）最新預估 2026 年全球石油需求將萎縮（此前預估成長），需求損失集中於 Q2。阿聯退出 OPEC 加劇供應管理不確定性。開發中經濟體通膨平均 5.1%。</p><hr><h2 id="🇹🇼-台灣重點補充" tabindex="-1">🇹🇼 台灣重點補充 <a class="header-anchor" href="#🇹🇼-台灣重點補充" aria-label="Permalink to &quot;🇹🇼 台灣重點補充&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">Q1 GDP 成長率概估</td><td style="text-align:left;">+13.69%（創近 39 年新高）</td></tr><tr><td style="text-align:left;">台股 4 月漲幅</td><td style="text-align:left;">+7,203 點（歷史最強單月）</td></tr><tr><td style="text-align:left;">台股總市值</td><td style="text-align:left;">4.47 兆美元（全球第六，超越英國）</td></tr><tr><td style="text-align:left;">5 月台股展望</td><td style="text-align:left;">短期震盪後挑戰 41,000 點</td></tr><tr><td style="text-align:left;">全年 GDP 預測</td><td style="text-align:left;">台經院 7.56% / 中經院 7.22% / 瑞銀 8%</td></tr><tr><td style="text-align:left;">Computex</td><td style="text-align:left;">6 月展會，5 月提前反映 AI 題材</td></tr><tr><td style="text-align:left;">關鍵風險</td><td style="text-align:left;">油價通膨、外資轉保守、新台幣貶值</td></tr></tbody></table><hr><h2 id="⚠️-風險警示" tabindex="-1">⚠️ 風險警示 <a class="header-anchor" href="#⚠️-風險警示" aria-label="Permalink to &quot;⚠️ 風險警示&quot;">​</a></h2><ol><li><strong>荷莫茲海峽封閉</strong>：2,000 艘船滯留，即使重開恢復需數月，全球糧食肥料供應鏈受嚴重衝擊</li><li><strong>油價高檔震盪</strong>：布蘭特 $111-$114 區間，IEA 下修全球需求，但供應中斷風險持續</li><li><strong>全球央行凍結降息</strong>：通膨威脅迫使央行暫停寬鬆，高利率環境延長</li><li><strong>中美關稅不確定性</strong>：IEEPA 退款 5/11 開始，但 Section 122 + Section 301 新關稅替代方案</li><li><strong>台股技術面警訊</strong>：漲幅過大、KD 高檔交叉、融資居高、外資轉保守</li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 模型：local/Qwen3.6-35B-A3B-4bit</em></p>',32)])])}const _=e(o,[["render",i]]);export{u as __pageData,_ as default};
